    "Remote neighbor interface counters and link parameters (to check for duplex/negotiation mismatch or remote errors)",
    "Physical-layer data: SFP/module type and status and cable test results (if available) to confirm hardware/cable issues"
  ]
}

{
  "intent": "check_and_fix",
  "intent_description": "R2 GigabitEthernet0/0/1 has 18 input_errors (RX-only). Likely physical-layer receive faults; goal: stop RX errors and restore clean input counters.",
  "target": "R2",
  "needs_fix": true,
  "plan": {
    "problem": "Receive-side input errors (18) on router2 interface GigabitEthernet0/0/1, likely caused by cable/SFP or remote PHY; telemetry lacks per-error breakdown.",
    "fix_summary": "Perform non-disruptive physical diagnostics, clear counters, soft-reset the interface, then replace transceiver/cable if errors persist.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "run_cable_test",
        "target": "GigabitEthernet0/0/1",
        "parameters": [
          "include_sfp_diagnostics=true"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "clear_interface_counters",
        "target": "GigabitEthernet0/0/1",
        "parameters": [
          "reason=baseline_after_diagnostics"
        ]
      },
      {
        "id": 3,
        "device": "router2",
        "action": "reset_interface",
        "target": "GigabitEthernet0/0/1",
        "parameters": [
          "method=soft_reset"
        ]
      },
      {
        "id": 4,
        "device": "router2",
        "action": "replace_sfp",
        "target": "GigabitEthernet0/0/1",
        "parameters": [
          "replace_with=known_good_transceiver_or_patch_cable"
        ]
      }
    ]
  }
}

